import{_ as t,o as a,c as s,ae as i}from"./chunks/framework.CNbcAk17.js";const u=JSON.parse('{"title":"Settings","description":"Understand Magma configuration files.","frontmatter":{"description":"Understand Magma configuration files."},"headers":[],"relativePath":"settings/index.md","filePath":"settings/index.md"}'),r={name:"settings/index.md"};function n(d,e,o,c,l,g){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>Magma stores durable configuration in the <code>config/</code> directory. In Docker deployments this directory is mounted as a volume so your settings survive container updates.</p><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>config/system.yaml</code></td><td>App-level settings such as background image, language, and dashboard grid cell size.</td></tr><tr><td><code>config/dashboard.yaml</code></td><td>Widgets, locations, search, network, theme, and integration references.</td></tr><tr><td><code>config/override.css</code></td><td>Custom CSS loaded after built-in styles.</td></tr><tr><td><code>config/passkey.yaml</code></td><td>Passkey credential storage.</td></tr></tbody></table><p>Secrets should not be committed to YAML. Store credential values in environment variables and reference the variable names in config.</p><h2 id="edit-paths" tabindex="-1">Edit paths <a class="header-anchor" href="#edit-paths" aria-label="Permalink to &quot;Edit paths&quot;">​</a></h2><ul><li>Use the dashboard editor for widget placement and property changes.</li><li>Use Settings for system settings, dashboard YAML, CSS override, and passkey editing.</li><li>Edit files directly when you want version control or bulk changes.</li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><p>Under <strong>Settings → Security</strong> you can register and manage <a href="/settings/passkeys">passkeys</a> that protect edit mode and settings access using biometrics (Face ID, Touch ID, Windows Hello).</p>',8)])])}const p=t(r,[["render",n]]);export{u as __pageData,p as default};
